-- ════════════════════════════════════════════════════════════
-- DataMEAL Academy — Cours KoboCollect ENRICHI (SVG + textes)
-- Remplace les leçons de MEAL-01 par la version illustrée
-- À exécuter dans Supabase SQL Editor
-- ════════════════════════════════════════════════════════════

DELETE FROM sms_lessons WHERE course_id = (SELECT id FROM sms_courses WHERE code = 'MEAL-01');
UPDATE sms_courses SET total_lessons = 7 WHERE code = 'MEAL-01';

INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Comprendre la collecte de données terrain', 'notebook', 10, 1, '{"cells": [{"type": "md", "content": "## Votre mission\n\nVous êtes recruté(e) comme agent MEAL pour une ONG qui intervient dans la région maritime du **Togo**. Une alerte nutritionnelle vient de tomber : il faut mesurer la malnutrition des enfants de 6 à 59 mois dans 5 districts de Lomé. Vous avez 10 jours et 8 enquêteurs.\n\nÀ la fin de ce projet, vous saurez **construire de A à Z** votre propre système de collecte KoboCollect — sans aucune connaissance préalable."}, {"type": "callout", "variant": "real", "title": "Pourquoi KoboToolbox ?", "content": "Avant les outils numériques, les enquêtes se faisaient sur papier : 200 questionnaires, 3 semaines de saisie manuelle, des erreurs partout. KoboToolbox (gratuit, utilisé par l''ONU, MSF, l''UNICEF) permet à un enquêteur avec un simple téléphone Android de collecter, géolocaliser et envoyer les données en temps réel."}, {"type": "md", "content": "## Les 3 grandes étapes de toute collecte\n\nGardez bien ces 3 étapes en tête, c''est le fil rouge de tout le projet :\n\n1. **Concevoir** le formulaire dans le navigateur (les questions à poser)\n2. **Déployer & collecter** sur le terrain avec l''app KoboCollect\n3. **Récupérer & analyser** les données reçues\n\nOn va commencer par créer un compte et un nouveau projet."}, {"type": "figure", "title": "Étape 1 — Créer un nouveau projet", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <!-- top bar -->\n    <rect width=\"560\" height=\"46\" fill=\"#0d9488\"/>\n    <text x=\"20\" y=\"29\" font-size=\"16\" font-weight=\"700\" fill=\"#fff\">KoboToolbox</text>\n    <rect x=\"440\" y=\"13\" width=\"100\" height=\"22\" rx=\"11\" fill=\"rgba(255,255,255,.2)\"/>\n    <text x=\"490\" y=\"28\" font-size=\"11\" fill=\"#fff\" text-anchor=\"middle\">Mon compte</text>\n    <!-- sidebar -->\n    <rect x=\"0\" y=\"46\" width=\"120\" height=\"314\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"16\" y=\"80\" font-size=\"12\" font-weight=\"600\" fill=\"#1e293b\">PROJETS</text>\n    <rect x=\"12\" y=\"92\" width=\"96\" height=\"26\" rx=\"6\" fill=\"#f1f5f9\"/>\n    <text x=\"20\" y=\"109\" font-size=\"11\" fill=\"#64748b\">Tous les projets</text>\n    <!-- main: empty state + NEW button -->\n    <text x=\"150\" y=\"90\" font-size=\"18\" font-weight=\"700\" fill=\"#1e293b\">Vos projets</text>\n    <text x=\"150\" y=\"114\" font-size=\"12\" fill=\"#64748b\">Aucun projet pour le moment</text>\n    <!-- NEW button highlighted -->\n    <rect x=\"430\" y=\"74\" width=\"110\" height=\"38\" rx=\"8\" fill=\"#0d9488\"/>\n    <text x=\"485\" y=\"98\" font-size=\"14\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">+ NEW</text>\n    <circle cx=\"540\" cy=\"70\" r=\"11\" fill=\"#0d9488\"/><text x=\"540\" y=\"74\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <!-- dialog -->\n    <rect x=\"180\" y=\"150\" width=\"300\" height=\"170\" rx=\"12\" fill=\"#fff\" stroke=\"#e2e8f0\" stroke-width=\"2\"/>\n    <text x=\"200\" y=\"180\" font-size=\"13\" font-weight=\"700\" fill=\"#1e293b\">Créer un projet</text>\n    <rect x=\"200\" y=\"196\" width=\"260\" height=\"40\" rx=\"8\" fill=\"#f1f5f9\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n    <text x=\"212\" y=\"214\" font-size=\"10\" fill=\"#64748b\">Nom du projet</text>\n    <text x=\"212\" y=\"229\" font-size=\"12\" font-weight=\"600\" fill=\"#1e293b\">Enquête nutrition Lomé 2025</text>\n    <circle cx=\"470\" cy=\"216\" r=\"11\" fill=\"#0d9488\"/><text x=\"470\" y=\"220\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n    <rect x=\"200\" y=\"246\" width=\"260\" height=\"32\" rx=\"6\" fill=\"#f1f5f9\"/>\n    <text x=\"212\" y=\"266\" font-size=\"11\" fill=\"#64748b\">Description (facultatif)</text>\n    <rect x=\"360\" y=\"288\" width=\"100\" height=\"30\" rx=\"8\" fill=\"#0d9488\"/>\n    <text x=\"410\" y=\"307\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">CRÉER</text>\n    <circle cx=\"470\" cy=\"303\" r=\"11\" fill=\"#0d9488\"/><text x=\"470\" y=\"307\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    </svg>", "caption": "Sur kf.kobotoolbox.org, après connexion : (1) cliquez le bouton vert NEW en haut à droite, (2) donnez un nom clair à votre projet — ici « Enquête nutrition Lomé 2025 » — et (3) cliquez CRÉER. Un nom de projet explicite vous évitera de vous perdre quand vous aurez plusieurs enquêtes."}, {"type": "resource", "title": "Créer un compte KoboToolbox gratuit", "url": "https://www.kobotoolbox.org/", "provider": "KoboToolbox", "desc": "Le serveur humanitaire est 100% gratuit pour les organisations à but non lucratif. Créez votre compte sur kf.kobotoolbox.org puis suivez les étapes ci-dessus."}, {"type": "quiz", "question": "Quelle est la toute première étape d''une collecte de données réussie ?", "opts": ["Acheter des téléphones", "Concevoir le formulaire (les questions)", "Recruter les enquêteurs", "Analyser les données"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Le constructeur de formulaire : ajouter une question', 'notebook', 15, 2, '{"cells": [{"type": "md", "content": "## Le Formbuilder, votre atelier\n\nUne fois le projet créé, KoboToolbox ouvre le **constructeur de formulaire** (Formbuilder). C''est ici qu''on ajoute les questions, une par une. Pas besoin de coder : tout se fait visuellement.\n\nChaque question a besoin de **deux choses** : un *libellé* (ce que lit l''enquêteur) et un *type de réponse* (texte, nombre, choix…)."}, {"type": "figure", "title": "Le constructeur de formulaire", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <rect width=\"560\" height=\"44\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"20\" y=\"28\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Constructeur de formulaire</text>\n    <rect x=\"440\" y=\"9\" width=\"60\" height=\"26\" rx=\"6\" fill=\"#0d9488\"/>\n    <text x=\"470\" y=\"26\" font-size=\"11\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">SAVE</text>\n    <rect x=\"506\" y=\"9\" width=\"44\" height=\"26\" rx=\"6\" fill=\"#f1f5f9\" stroke=\"#e2e8f0\"/>\n    <text x=\"528\" y=\"26\" font-size=\"10\" fill=\"#64748b\" text-anchor=\"middle\">Aperçu</text>\n    <!-- existing question card -->\n    <rect x=\"40\" y=\"64\" width=\"480\" height=\"58\" rx=\"10\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <rect x=\"40\" y=\"64\" width=\"5\" height=\"58\" rx=\"2\" fill=\"#0d9488\"/>\n    <text x=\"60\" y=\"86\" font-size=\"10\" fill=\"#64748b\">Question 1 · Texte</text>\n    <text x=\"60\" y=\"106\" font-size=\"13\" font-weight=\"600\" fill=\"#1e293b\">Nom de l''enquêteur</text>\n    <text x=\"490\" y=\"98\" font-size=\"18\" fill=\"#64748b\">⚙</text>\n    <!-- ADD QUESTION button (the + below) -->\n    <circle cx=\"280\" cy=\"150\" r=\"18\" fill=\"#0d9488\"/>\n    <text x=\"280\" y=\"157\" font-size=\"22\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">+</text>\n    <circle cx=\"310\" cy=\"138\" r=\"11\" fill=\"#0d9488\"/><text x=\"310\" y=\"142\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <text x=\"280\" y=\"190\" font-size=\"11\" fill=\"#64748b\" text-anchor=\"middle\">Cliquez le + pour ajouter une question</text>\n    <!-- new question input -->\n    <rect x=\"40\" y=\"208\" width=\"480\" height=\"120\" rx=\"10\" fill=\"#fff\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n    <rect x=\"56\" y=\"224\" width=\"360\" height=\"34\" rx=\"6\" fill=\"#f1f5f9\"/>\n    <text x=\"66\" y=\"246\" font-size=\"13\" fill=\"#1e293b\">Quel est l''âge de l''enfant (en mois) ?</text>\n    <circle cx=\"400\" cy=\"241\" r=\"11\" fill=\"#0d9488\"/><text x=\"400\" y=\"245\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n    <rect x=\"430\" y=\"224\" width=\"74\" height=\"34\" rx=\"6\" fill=\"#0d9488\"/>\n    <text x=\"467\" y=\"245\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">+ AJOUTER</text>\n    <text x=\"56\" y=\"284\" font-size=\"11\" fill=\"#64748b\">Type de réponse :</text>\n    <rect x=\"56\" y=\"292\" width=\"120\" height=\"28\" rx=\"6\" fill=\"#fff\" stroke=\"#0d9488\"/>\n    <text x=\"66\" y=\"310\" font-size=\"11\" font-weight=\"600\" fill=\"#0d9488\">Nombre entier ▾</text>\n    <circle cx=\"186\" cy=\"306\" r=\"11\" fill=\"#0d9488\"/><text x=\"186\" y=\"310\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    </svg>", "caption": "(1) Cliquez sur le bouton **+** rond qui apparaît sous chaque question pour en ajouter une nouvelle. (2) Tapez le libellé de la question tel qu''il s''affichera sur le téléphone — par exemple « Quel est l''âge de l''enfant (en mois) ? ». (3) Choisissez ensuite le type de réponse attendu. En haut à droite, n''oubliez jamais le bouton **SAVE** pour enregistrer votre travail."}, {"type": "callout", "variant": "tip", "title": "Libellé clair = données propres", "content": "Rédigez vos questions exactement comme l''enquêteur doit les poser, dans la langue du terrain. Une question ambiguë (« Âge ? ») donne des réponses incohérentes (années ? mois ?). Une question précise (« Âge de l''enfant en mois ? ») donne des données fiables."}, {"type": "md", "content": "## Le nom technique (généré automatiquement)\n\nKoboToolbox crée automatiquement un **nom** technique pour chaque question (ex. `age_months`). C''est ce nom qu''on retrouvera comme **colonne** dans le tableau de données final. Bonne pratique : renommez-le proprement (pas d''espaces, pas d''accents) pour faciliter l''analyse plus tard."}, {"type": "quiz", "question": "Que tapez-vous en premier quand vous ajoutez une question dans le Formbuilder ?", "opts": ["Le code Python", "Le libellé de la question (ce que lit l''enquêteur)", "Le mot de passe", "L''adresse GPS"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Choisir le bon type de réponse', 'notebook', 15, 3, '{"cells": [{"type": "md", "content": "## Le type de réponse : la décision la plus importante\n\nLe **type** détermine comment l''enquêteur saisit la donnée et comment vous l''analyserez. Choisir le bon type dès le départ vous évite des heures de nettoyage.\n\n> ⚠️ Important : dans le Formbuilder, **une fois le type choisi, on ne peut plus le changer**. Pour en changer, il faut supprimer la question et la recréer. Choisissez donc bien du premier coup."}, {"type": "figure", "title": "Les principaux types de réponse", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <text x=\"20\" y=\"32\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Choisir le bon type de réponse</text>\n    <circle cx=\"300\" cy=\"27\" r=\"11\" fill=\"#0d9488\"/><text x=\"300\" y=\"31\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <!-- list of types -->\n    <g font-size=\"12\">\n    <rect x=\"20\" y=\"48\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"34\" y=\"68\" font-size=\"16\">🔤</text><text x=\"58\" y=\"66\" font-weight=\"600\" fill=\"#1e293b\">Texte</text>\n    <text x=\"58\" y=\"82\" font-size=\"10\" fill=\"#64748b\">Réponse libre (nom, commentaire)</text>\n\n    <rect x=\"20\" y=\"100\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"34\" y=\"120\" font-size=\"16\">🔢</text><text x=\"58\" y=\"118\" font-weight=\"600\" fill=\"#1e293b\">Nombre entier</text>\n    <text x=\"58\" y=\"134\" font-size=\"10\" fill=\"#64748b\">Âge, effectif, comptage</text>\n\n    <rect x=\"20\" y=\"152\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"34\" y=\"172\" font-size=\"16\">📊</text><text x=\"58\" y=\"170\" font-weight=\"600\" fill=\"#1e293b\">Décimal</text>\n    <text x=\"58\" y=\"186\" font-size=\"10\" fill=\"#64748b\">Poids, taille, MUAC (mm)</text>\n\n    <rect x=\"285\" y=\"48\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n    <text x=\"299\" y=\"68\" font-size=\"16\">☑️</text><text x=\"323\" y=\"66\" font-weight=\"600\" fill=\"#0d9488\">Choix unique</text>\n    <text x=\"323\" y=\"82\" font-size=\"10\" fill=\"#64748b\">Sexe, district (1 seule réponse)</text>\n    <circle cx=\"528\" cy=\"56\" r=\"11\" fill=\"#0d9488\"/><text x=\"528\" y=\"60\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n\n    <rect x=\"285\" y=\"100\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"299\" y=\"120\" font-size=\"16\">✅</text><text x=\"323\" y=\"118\" font-weight=\"600\" fill=\"#1e293b\">Choix multiple</text>\n    <text x=\"323\" y=\"134\" font-size=\"10\" fill=\"#64748b\">Plusieurs réponses possibles</text>\n\n    <rect x=\"285\" y=\"152\" width=\"255\" height=\"44\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"299\" y=\"172\" font-size=\"16\">📍</text><text x=\"323\" y=\"170\" font-weight=\"600\" fill=\"#1e293b\">Point GPS</text>\n    <text x=\"323\" y=\"186\" font-size=\"10\" fill=\"#64748b\">Localiser le ménage</text>\n    </g>\n    <!-- choices panel for select_one -->\n    <rect x=\"20\" y=\"212\" width=\"520\" height=\"128\" rx=\"10\" fill=\"#fff\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n    <text x=\"36\" y=\"236\" font-size=\"12\" font-weight=\"700\" fill=\"#1e293b\">Options de réponse (Choix unique : Sexe)</text>\n    <circle cx=\"330\" cy=\"230\" r=\"11\" fill=\"#0d9488\"/><text x=\"330\" y=\"234\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    <rect x=\"36\" y=\"248\" width=\"220\" height=\"30\" rx=\"6\" fill=\"#f1f5f9\"/>\n    <text x=\"48\" y=\"268\" font-size=\"12\" fill=\"#1e293b\">Masculin</text>\n    <rect x=\"36\" y=\"284\" width=\"220\" height=\"30\" rx=\"6\" fill=\"#f1f5f9\"/>\n    <text x=\"48\" y=\"304\" font-size=\"12\" fill=\"#1e293b\">Féminin</text>\n    <circle cx=\"280\" cy=\"300\" r=\"13\" fill=\"#0d9488\"/>\n    <text x=\"280\" y=\"305\" font-size=\"16\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">+</text>\n    <text x=\"300\" y=\"305\" font-size=\"11\" fill=\"#64748b\">Ajouter une option</text>\n    </svg>", "caption": "(1) Pour chaque question, choisissez le type adapté. (2) Pour notre enquête : « Sexe » et « District » sont des **Choix unique** (une seule réponse dans une liste). (3) Quand vous choisissez « Choix unique » ou « Choix multiple », vous ajoutez les options juste en dessous (Masculin / Féminin). Cliquez le **+** pour ajouter chaque option."}, {"type": "md", "content": "## Quel type pour quelle donnée ? (mémo)\n\nVoici comment choisir pour notre enquête nutritionnelle :\n\n- **Texte** → nom de l''enquêteur, nom de l''enfant (réponse libre)\n- **Nombre entier** → âge en mois (pas de virgule)\n- **Décimal** → MUAC en mm, poids en kg (avec virgule)\n- **Choix unique** → sexe (M/F), district (une seule réponse)\n- **Choix multiple** → symptômes observés (plusieurs réponses)\n- **Point GPS** → position du ménage"}, {"type": "callout", "variant": "tip", "title": "Privilégiez les choix aux textes libres", "content": "Chaque fois que vous pouvez prévoir les réponses possibles, utilisez « Choix unique » plutôt que « Texte ». Pourquoi ? Un texte libre génère « Lomé », « lome », « LOME », « Lomé-ville »… impossible à analyser. Une liste de choix garantit des données propres et directement exploitables."}, {"type": "quiz", "question": "Vous voulez collecter le MUAC en millimètres (ex. 118.5 mm). Quel type choisissez-vous ?", "opts": ["Texte", "Nombre entier", "Décimal", "Choix unique"], "ans": 2}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Rendre le formulaire intelligent (validation & logique)', 'notebook', 20, 4, '{"cells": [{"type": "md", "content": "## Empêcher les erreurs AVANT qu''elles arrivent\n\nUn bon formulaire ne fait pas que poser des questions : il **empêche les erreurs de saisie** sur le terrain. Trois réglages avancés, accessibles via l''icône **⚙ Settings** de chaque question, font toute la différence."}, {"type": "figure", "title": "Les réglages avancés d''une question (⚙)", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <text x=\"20\" y=\"30\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Réglages avancés d''une question ⚙</text>\n    <circle cx=\"330\" cy=\"25\" r=\"11\" fill=\"#0d9488\"/><text x=\"330\" y=\"29\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <rect x=\"20\" y=\"46\" width=\"520\" height=\"300\" rx=\"12\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"40\" y=\"76\" font-size=\"13\" font-weight=\"700\" fill=\"#0d9488\">MUAC (mm) — Décimal</text>\n\n    <!-- required toggle -->\n    <text x=\"40\" y=\"110\" font-size=\"12\" fill=\"#1e293b\">Réponse obligatoire</text>\n    <rect x=\"460\" y=\"98\" width=\"44\" height=\"22\" rx=\"11\" fill=\"#0d9488\"/>\n    <circle cx=\"493\" cy=\"109\" r=\"8\" fill=\"#fff\"/>\n    <circle cx=\"524\" cy=\"109\" r=\"11\" fill=\"#0d9488\"/><text x=\"524\" y=\"113\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n\n    <line x1=\"40\" y1=\"130\" x2=\"520\" y2=\"130\" stroke=\"#e2e8f0\"/>\n    <!-- validation -->\n    <text x=\"40\" y=\"156\" font-size=\"12\" font-weight=\"600\" fill=\"#1e293b\">Critère de validation</text>\n    <text x=\"40\" y=\"174\" font-size=\"10\" fill=\"#64748b\">Empêche les valeurs absurdes lors de la saisie</text>\n    <rect x=\"40\" y=\"184\" width=\"464\" height=\"30\" rx=\"6\" fill=\"#f1f5f9\" stroke=\"#0d9488\"/>\n    <text x=\"52\" y=\"204\" font-size=\"12\" font-family=\"monospace\" fill=\"#0d9488\">. &gt; 50 and . &lt; 300</text>\n    <circle cx=\"524\" cy=\"199\" r=\"11\" fill=\"#0d9488\"/><text x=\"524\" y=\"203\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    <text x=\"40\" y=\"232\" font-size=\"10\" fill=\"#64748b\">Message si erreur : « Le MUAC doit être entre 50 et 300 mm »</text>\n\n    <line x1=\"40\" y1=\"248\" x2=\"520\" y2=\"248\" stroke=\"#e2e8f0\"/>\n    <!-- skip logic -->\n    <text x=\"40\" y=\"274\" font-size=\"12\" font-weight=\"600\" fill=\"#1e293b\">Logique d''affichage (skip logic)</text>\n    <text x=\"40\" y=\"292\" font-size=\"10\" fill=\"#64748b\">N''afficher cette question que si une condition est vraie</text>\n    <rect x=\"40\" y=\"302\" width=\"464\" height=\"30\" rx=\"6\" fill=\"#f1f5f9\" stroke=\"#e2e8f0\"/>\n    <text x=\"52\" y=\"322\" font-size=\"12\" font-family=\"monospace\" fill=\"#1e293b\">${sexe} = ''F''</text>\n    <circle cx=\"524\" cy=\"317\" r=\"11\" fill=\"#0d9488\"/><text x=\"524\" y=\"321\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">4</text>\n    </svg>", "caption": "(1) Cliquez l''icône ⚙ à droite d''une question pour ouvrir ses réglages. (2) « Réponse obligatoire » empêche de sauter la question. (3) « Critère de validation » bloque les valeurs absurdes : ici `. > 50 and . < 300` refuse tout MUAC hors de la plage réaliste. (4) « Logique d''affichage » (skip logic) n''affiche la question que si une condition est vraie."}, {"type": "md", "content": "## 1. Validation — le point `.` représente « cette réponse »\n\nDans un critère de validation, le point `.` signifie « la valeur saisie pour cette question ». Exemples :\n\n- Âge entre 6 et 59 mois : `. >= 6 and . <= 59`\n- MUAC réaliste : `. > 50 and . < 300`\n\nSi l''enquêteur tape une valeur hors limites, KoboCollect refuse et affiche votre message d''erreur."}, {"type": "callout", "variant": "warning", "title": "Erreur fréquente des débutants", "content": "On écrit `. >= 6` et NON `age_months >= 6`. Le point représente la question courante. Pour référencer une AUTRE question (dans la skip logic), on utilise la syntaxe ${nom_de_la_question}, par exemple ${sexe} = ''F''."}, {"type": "md", "content": "## 2. Skip logic — afficher selon une réponse précédente\n\nLa **logique d''affichage** n''affiche une question que si une condition est remplie. Exemple : ne poser « Nombre de grossesses » que si `${sexe} = ''F''`. Sur le terrain, l''enquêteur ne voit que les questions pertinentes — formulaire plus court, moins d''erreurs."}, {"type": "embed", "title": "Notebook live : tester votre logique de validation", "code": "# Simulons la validation que KoboCollect applique sur le terrain\ndef valider_muac(valeur):\n    if not (50 < valeur < 300):\n        return f\"REFUSE : {valeur} mm est hors plage (50-300)\"\n    return f\"OK : {valeur} mm accepte\"\n\nfor v in [118.5, 5, 400, 125]:\n    print(valider_muac(v))"}, {"type": "quiz", "question": "Comment n''afficher une question QUE si le sexe saisi est ''F'' (féminin) ?", "opts": ["validation: sexe = F", "relevant / skip logic : ${sexe} = ''F''", "obligatoire : oui", "type : féminin"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Déployer le formulaire et lancer la collecte', 'notebook', 15, 5, '{"cells": [{"type": "md", "content": "## Du brouillon au terrain\n\nVotre formulaire est conçu et enregistré. Mais il est encore en **brouillon** : personne ne peut encore collecter. Il faut le **déployer**. Une fois déployé, KoboToolbox vous donne deux moyens de collecter."}, {"type": "figure", "title": "Étape de déploiement (onglet FORM → DEPLOY)", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <rect width=\"560\" height=\"44\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"20\" y=\"28\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Page du projet — onglet FORM</text>\n    <!-- tabs -->\n    <text x=\"40\" y=\"74\" font-size=\"12\" font-weight=\"700\" fill=\"#0d9488\">SUMMARY</text>\n    <text x=\"120\" y=\"74\" font-size=\"12\" font-weight=\"700\" fill=\"#1e293b\">FORM</text>\n    <line x1=\"118\" y1=\"82\" x2=\"155\" y2=\"82\" stroke=\"#0d9488\" stroke-width=\"3\"/>\n    <text x=\"190\" y=\"74\" font-size=\"12\" fill=\"#64748b\">DATA</text>\n    <text x=\"250\" y=\"74\" font-size=\"12\" fill=\"#64748b\">SETTINGS</text>\n    <!-- deploy card -->\n    <rect x=\"40\" y=\"100\" width=\"480\" height=\"90\" rx=\"12\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"60\" y=\"132\" font-size=\"13\" font-weight=\"700\" fill=\"#1e293b\">Votre formulaire est prêt (brouillon)</text>\n    <text x=\"60\" y=\"154\" font-size=\"11\" fill=\"#64748b\">Déployez-le pour commencer à collecter des données</text>\n    <rect x=\"370\" y=\"124\" width=\"130\" height=\"44\" rx=\"10\" fill=\"#16a34a\"/>\n    <text x=\"435\" y=\"151\" font-size=\"14\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">▶ DEPLOY</text>\n    <circle cx=\"508\" cy=\"122\" r=\"11\" fill=\"#0d9488\"/><text x=\"508\" y=\"126\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <!-- collect options -->\n    <text x=\"40\" y=\"222\" font-size=\"13\" font-weight=\"700\" fill=\"#1e293b\">Collecter les données</text>\n    <circle cx=\"220\" cy=\"217\" r=\"11\" fill=\"#0d9488\"/><text x=\"220\" y=\"221\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n    <rect x=\"40\" y=\"236\" width=\"235\" height=\"100\" rx=\"12\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"60\" y=\"264\" font-size=\"22\">🌐</text>\n    <text x=\"92\" y=\"262\" font-size=\"12\" font-weight=\"600\" fill=\"#1e293b\">Navigateur web</text>\n    <text x=\"60\" y=\"290\" font-size=\"10\" fill=\"#64748b\">Copier le lien et l''ouvrir sur</text>\n    <text x=\"60\" y=\"304\" font-size=\"10\" fill=\"#64748b\">n''importe quel téléphone/PC</text>\n    <rect x=\"60\" y=\"312\" width=\"160\" height=\"16\" rx=\"4\" fill=\"#f1f5f9\"/>\n    <text x=\"68\" y=\"324\" font-size=\"9\" font-family=\"monospace\" fill=\"#0d9488\">ee.kobotoolbox.org/x/AbC123</text>\n\n    <rect x=\"285\" y=\"236\" width=\"235\" height=\"100\" rx=\"12\" fill=\"#fff\" stroke=\"#0d9488\" stroke-width=\"2\"/>\n    <text x=\"305\" y=\"264\" font-size=\"22\">📱</text>\n    <text x=\"337\" y=\"262\" font-size=\"12\" font-weight=\"600\" fill=\"#0d9488\">App KoboCollect</text>\n    <text x=\"305\" y=\"290\" font-size=\"10\" fill=\"#64748b\">Android · collecte hors-ligne</text>\n    <text x=\"305\" y=\"304\" font-size=\"10\" fill=\"#64748b\">idéale pour le terrain</text>\n    <circle cx=\"508\" cy=\"244\" r=\"11\" fill=\"#0d9488\"/><text x=\"508\" y=\"248\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    </svg>", "caption": "(1) Dans l''onglet FORM de votre projet, cliquez le bouton vert **DEPLOY** pour activer le formulaire. (2) La section « Collecter les données » apparaît avec deux options : (web) copier un lien à ouvrir dans n''importe quel navigateur, ou (3) **l''app KoboCollect** sur Android, idéale pour le terrain car elle fonctionne **hors-ligne**."}, {"type": "md", "content": "## Web ou application mobile ?\n\n- **Lien web (Enketo)** : pratique pour quelques saisies sur ordinateur ou pour tester. Nécessite une connexion internet.\n- **App KoboCollect (Android)** : LA solution terrain. Elle télécharge le formulaire une fois, puis fonctionne **entièrement hors-ligne** — l''enquêteur collecte dans un village sans réseau, et synchronise dès qu''il retrouve une connexion."}, {"type": "callout", "variant": "real", "title": "Le terrain en Afrique de l''Ouest", "content": "Dans beaucoup de zones rurales, il n''y a pas de réseau. C''est précisément pour ça que l''app KoboCollect est conçue pour le hors-ligne : vos 8 enquêteurs collectent toute la journée dans les villages, puis synchronisent le soir au bureau ou dès qu''une barre de réseau apparaît. Aucune donnée perdue."}, {"type": "resource", "title": "Télécharger l''app KoboCollect (Android, gratuit)", "url": "https://play.google.com/store/apps/details?id=org.koboc.collect.android", "provider": "Google Play", "desc": "L''application mobile officielle pour la collecte hors-ligne. Installez-la, configurez le serveur kf.kobotoolbox.org, et vos enquêteurs sont prêts."}, {"type": "quiz", "question": "Votre formulaire est conçu mais personne ne peut collecter. Que devez-vous faire ?", "opts": ["Le supprimer", "Cliquer DEPLOY pour le déployer", "Changer de navigateur", "Attendre 24h"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Collecter sur le terrain avec KoboCollect', 'notebook', 15, 6, '{"cells": [{"type": "md", "content": "## L''enquêteur en action\n\nVoyons concrètement comment l''enquêteur utilise l''app KoboCollect sur son téléphone, du premier réglage à l''envoi des données."}, {"type": "figure", "title": "Le parcours de collecte sur mobile (3 étapes)", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <text x=\"20\" y=\"30\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Collecte terrain — App KoboCollect (Android)</text>\n    <!-- phone 1: config server -->\n    <rect x=\"40\" y=\"50\" width=\"150\" height=\"280\" rx=\"18\" fill=\"#1e293b\"/>\n    <rect x=\"48\" y=\"64\" width=\"134\" height=\"252\" rx=\"6\" fill=\"#fff\"/>\n    <rect x=\"48\" y=\"64\" width=\"134\" height=\"34\" fill=\"#0d9488\"/>\n    <text x=\"115\" y=\"86\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">Paramètres serveur</text>\n    <text x=\"58\" y=\"120\" font-size=\"8\" fill=\"#64748b\">URL du serveur</text>\n    <rect x=\"58\" y=\"126\" width=\"114\" height=\"22\" rx=\"4\" fill=\"#f1f5f9\"/>\n    <text x=\"63\" y=\"141\" font-size=\"7\" font-family=\"monospace\" fill=\"#0d9488\">kf.kobotoolbox.org</text>\n    <text x=\"58\" y=\"170\" font-size=\"8\" fill=\"#64748b\">Nom d''utilisateur</text>\n    <rect x=\"58\" y=\"176\" width=\"114\" height=\"22\" rx=\"4\" fill=\"#f1f5f9\"/>\n    <circle cx=\"180\" cy=\"100\" r=\"11\" fill=\"#0d9488\"/><text x=\"180\" y=\"104\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <text x=\"115\" y=\"300\" font-size=\"8\" fill=\"#64748b\" text-anchor=\"middle\">1. Connexion au serveur</text>\n\n    <!-- phone 2: fill form -->\n    <rect x=\"205\" y=\"50\" width=\"150\" height=\"280\" rx=\"18\" fill=\"#1e293b\"/>\n    <rect x=\"213\" y=\"64\" width=\"134\" height=\"252\" rx=\"6\" fill=\"#fff\"/>\n    <rect x=\"213\" y=\"64\" width=\"134\" height=\"34\" fill=\"#0d9488\"/>\n    <text x=\"280\" y=\"86\" font-size=\"9\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">Enquête nutrition</text>\n    <text x=\"223\" y=\"120\" font-size=\"8\" fill=\"#1e293b\">Âge (mois)</text>\n    <rect x=\"223\" y=\"126\" width=\"114\" height=\"20\" rx=\"4\" fill=\"#f1f5f9\"/>\n    <text x=\"229\" y=\"140\" font-size=\"9\" fill=\"#1e293b\">23</text>\n    <text x=\"223\" y=\"166\" font-size=\"8\" fill=\"#1e293b\">MUAC (mm)</text>\n    <rect x=\"223\" y=\"172\" width=\"114\" height=\"20\" rx=\"4\" fill=\"#f1f5f9\"/>\n    <text x=\"229\" y=\"186\" font-size=\"9\" fill=\"#1e293b\">118.5</text>\n    <text x=\"223\" y=\"212\" font-size=\"8\" fill=\"#1e293b\">Position GPS 📍</text>\n    <rect x=\"223\" y=\"218\" width=\"114\" height=\"28\" rx=\"4\" fill=\"#ecfdf5\" stroke=\"#16a34a\"/>\n    <text x=\"229\" y=\"230\" font-size=\"7\" fill=\"#16a34a\">✓ 6.1834, 1.3421</text>\n    <text x=\"229\" y=\"240\" font-size=\"6\" fill=\"#64748b\">précision ±4m</text>\n    <circle cx=\"345\" cy=\"100\" r=\"11\" fill=\"#0d9488\"/><text x=\"345\" y=\"104\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n    <text x=\"280\" y=\"300\" font-size=\"8\" fill=\"#64748b\" text-anchor=\"middle\">2. Remplir (hors-ligne OK)</text>\n\n    <!-- phone 3: send -->\n    <rect x=\"370\" y=\"50\" width=\"150\" height=\"280\" rx=\"18\" fill=\"#1e293b\"/>\n    <rect x=\"378\" y=\"64\" width=\"134\" height=\"252\" rx=\"6\" fill=\"#fff\"/>\n    <rect x=\"378\" y=\"64\" width=\"134\" height=\"34\" fill=\"#0d9488\"/>\n    <text x=\"445\" y=\"86\" font-size=\"9\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">Envoyer les fiches</text>\n    <rect x=\"388\" y=\"116\" width=\"114\" height=\"30\" rx=\"6\" fill=\"#ecfdf5\"/>\n    <text x=\"396\" y=\"135\" font-size=\"9\" fill=\"#16a34a\">✓ 47 fiches prêtes</text>\n    <rect x=\"388\" y=\"250\" width=\"114\" height=\"34\" rx=\"8\" fill=\"#0d9488\"/>\n    <text x=\"445\" y=\"272\" font-size=\"10\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">📤 ENVOYER</text>\n    <circle cx=\"510\" cy=\"100\" r=\"11\" fill=\"#0d9488\"/><text x=\"510\" y=\"104\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text>\n    <text x=\"445\" y=\"300\" font-size=\"8\" fill=\"#64748b\" text-anchor=\"middle\">3. Synchroniser au réseau</text>\n    </svg>", "caption": "(1) **Configuration** : une seule fois, l''enquêteur renseigne l''URL du serveur (kf.kobotoolbox.org) et ses identifiants. (2) **Remplissage** : il ouvre l''enquête, saisit les réponses ; le champ GPS capture automatiquement la position du ménage avec sa précision. Tout fonctionne hors-ligne. (3) **Envoi** : de retour dans une zone couverte, il appuie sur ENVOYER pour synchroniser toutes les fiches collectées vers le serveur."}, {"type": "md", "content": "## Le champ GPS : la clé de la cartographie\n\nQuand l''enquêteur appuie sur le champ **Point GPS**, le téléphone capture latitude + longitude + précision. Ces coordonnées sont précieuses : au **Projet 2**, vous les utiliserez pour cartographier tous les ménages dans QGIS et identifier les zones les plus touchées.\n\nConseil terrain : attendez que la précision descende sous ±5 m avant d''enregistrer le point."}, {"type": "callout", "variant": "tip", "title": "Contrôle qualité dès la collecte", "content": "Grâce aux validations que vous avez configurées (leçon 4), l''app refuse en direct les valeurs absurdes. L''enquêteur corrige immédiatement, sur place — bien plus fiable qu''une correction au bureau trois semaines plus tard quand on ne se souvient plus du contexte."}, {"type": "quiz", "question": "Pourquoi l''app KoboCollect est-elle idéale pour les zones rurales sans réseau ?", "opts": ["Elle est plus jolie", "Elle fonctionne hors-ligne puis synchronise quand le réseau revient", "Elle ne capture pas le GPS", "Elle envoie des SMS"], "ans": 1}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';
INSERT INTO sms_lessons (course_id, title, type, points, order_index, content) SELECT id, 'Récupérer et analyser les données (capstone)', 'notebook', 20, 7, '{"cells": [{"type": "md", "content": "## Les données arrivent !\n\nVos 8 enquêteurs ont synchronisé leurs fiches. Direction l''onglet **DATA** de votre projet pour voir les soumissions arriver en temps réel."}, {"type": "figure", "title": "Visualiser les données reçues (onglet DATA)", "svg": "<svg viewBox=\"0 0 560 360\" xmlns=\"http://www.w3.org/2000/svg\" style=\"max-width:100%;height:auto;font-family:system-ui,-apple-system,sans-serif\">\n    <rect width=\"560\" height=\"360\" fill=\"#f1f5f9\"/>\n    <rect width=\"560\" height=\"44\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <text x=\"20\" y=\"28\" font-size=\"14\" font-weight=\"700\" fill=\"#1e293b\">Données reçues — onglet DATA</text>\n    <circle cx=\"330\" cy=\"23\" r=\"11\" fill=\"#0d9488\"/><text x=\"330\" y=\"27\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">1</text>\n    <text x=\"40\" y=\"74\" font-size=\"12\" fill=\"#64748b\">SUMMARY</text>\n    <text x=\"120\" y=\"74\" font-size=\"12\" fill=\"#64748b\">FORM</text>\n    <text x=\"190\" y=\"74\" font-size=\"12\" font-weight=\"700\" fill=\"#0d9488\">DATA</text>\n    <line x1=\"188\" y1=\"82\" x2=\"218\" y2=\"82\" stroke=\"#0d9488\" stroke-width=\"3\"/>\n    <!-- counter -->\n    <rect x=\"40\" y=\"92\" width=\"160\" height=\"40\" rx=\"10\" fill=\"#0d9488\"/>\n    <text x=\"56\" y=\"110\" font-size=\"9\" fill=\"rgba(255,255,255,.8)\">Soumissions reçues</text>\n    <text x=\"56\" y=\"126\" font-size=\"16\" font-weight=\"800\" fill=\"#fff\">200 fiches</text>\n    <!-- table -->\n    <rect x=\"40\" y=\"146\" width=\"480\" height=\"180\" rx=\"8\" fill=\"#fff\" stroke=\"#e2e8f0\"/>\n    <rect x=\"40\" y=\"146\" width=\"480\" height=\"28\" fill=\"#f1f5f9\"/>\n    <text x=\"54\" y=\"165\" font-size=\"10\" font-weight=\"700\" fill=\"#1e293b\">ID</text>\n    <text x=\"140\" y=\"165\" font-size=\"10\" font-weight=\"700\" fill=\"#1e293b\">District</text>\n    <text x=\"250\" y=\"165\" font-size=\"10\" font-weight=\"700\" fill=\"#1e293b\">Âge</text>\n    <text x=\"320\" y=\"165\" font-size=\"10\" font-weight=\"700\" fill=\"#1e293b\">MUAC</text>\n    <text x=\"420\" y=\"165\" font-size=\"10\" font-weight=\"700\" fill=\"#1e293b\">GPS</text>\n    <circle cx=\"500\" cy=\"160\" r=\"11\" fill=\"#0d9488\"/><text x=\"500\" y=\"164\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">2</text>\n    <rect x=\"40\" y=\"176\" width=\"480\" height=\"28\" fill=\"#fafafa\"/><text x=\"54\" y=\"192\" font-size=\"10\" fill=\"#1e293b\">TG-001</text><text x=\"140\" y=\"192\" font-size=\"10\" fill=\"#1e293b\">Agoè</text><text x=\"250\" y=\"192\" font-size=\"10\" fill=\"#1e293b\">23</text><text x=\"320\" y=\"192\" font-size=\"10\" font-weight=\"600\" fill=\"#1e293b\">127.3</text><text x=\"420\" y=\"192\" font-size=\"10\">📍</text><rect x=\"40\" y=\"204\" width=\"480\" height=\"28\" fill=\"#fff\"/><text x=\"54\" y=\"220\" font-size=\"10\" fill=\"#1e293b\">TG-002</text><text x=\"140\" y=\"220\" font-size=\"10\" fill=\"#1e293b\">Golfe</text><text x=\"250\" y=\"220\" font-size=\"10\" fill=\"#1e293b\">41</text><text x=\"320\" y=\"220\" font-size=\"10\" font-weight=\"600\" fill=\"#1e293b\">145.2</text><text x=\"420\" y=\"220\" font-size=\"10\">📍</text><rect x=\"40\" y=\"232\" width=\"480\" height=\"28\" fill=\"#fafafa\"/><text x=\"54\" y=\"248\" font-size=\"10\" fill=\"#1e293b\">TG-003</text><text x=\"140\" y=\"248\" font-size=\"10\" fill=\"#1e293b\">Zio</text><text x=\"250\" y=\"248\" font-size=\"10\" fill=\"#1e293b\">15</text><text x=\"320\" y=\"248\" font-size=\"10\" font-weight=\"600\" fill=\"#d97706\">118.6</text><text x=\"420\" y=\"248\" font-size=\"10\">📍</text><rect x=\"40\" y=\"260\" width=\"480\" height=\"28\" fill=\"#fff\"/><text x=\"54\" y=\"276\" font-size=\"10\" fill=\"#1e293b\">TG-004</text><text x=\"140\" y=\"276\" font-size=\"10\" fill=\"#1e293b\">Bas-Mono</text><text x=\"250\" y=\"276\" font-size=\"10\" fill=\"#1e293b\">30</text><text x=\"320\" y=\"276\" font-size=\"10\" font-weight=\"600\" fill=\"#dc2626\">112.0</text><text x=\"420\" y=\"276\" font-size=\"10\">📍</text><rect x=\"40\" y=\"288\" width=\"480\" height=\"28\" fill=\"#fafafa\"/><text x=\"54\" y=\"304\" font-size=\"10\" fill=\"#1e293b\">TG-005</text><text x=\"140\" y=\"304\" font-size=\"10\" fill=\"#1e293b\">Lacs</text><text x=\"250\" y=\"304\" font-size=\"10\" fill=\"#1e293b\">52</text><text x=\"320\" y=\"304\" font-size=\"10\" font-weight=\"600\" fill=\"#1e293b\">134.8</text><text x=\"420\" y=\"304\" font-size=\"10\">📍</text><text x=\"54\" y=\"320\" font-size=\"9\" fill=\"#64748b\">Telechargeable en XLSX, CSV ou via API, puis analyse Python</text><circle cx=\"500\" cy=\"314\" r=\"11\" fill=\"#0d9488\"/><text x=\"500\" y=\"318\" font-size=\"12\" font-weight=\"700\" fill=\"#fff\" text-anchor=\"middle\">3</text></svg>", "caption": "(1) Cliquez l''onglet **DATA** de votre projet. (2) Un tableau affiche toutes les soumissions, une ligne par enfant enquêté, avec chaque question en colonne. (3) Vous pouvez tout télécharger en Excel (XLSX), CSV, ou le récupérer par **API** pour l''analyser directement en Python — exactement ce qu''on va faire maintenant."}, {"type": "md", "content": "## De la donnée brute à la décision\n\nLe but du MEAL n''est pas de produire des chiffres, mais d''**éclairer une décision** : faut-il déclencher une réponse nutritionnelle d''urgence ? On analyse les données reçues selon les seuils OMS/SPHERE :\n\n- MUAC < 115 mm → **MAS** (malnutrition aiguë sévère)\n- 115–125 mm → **MAM** (modérée)\n- ≥ 125 mm → Normal\n\nSi la prévalence MAG (MAS+MAM) dépasse **15%**, c''est une urgence selon les standards SPHERE."}, {"type": "embed", "title": "Notebook live : analyser vos données KoboCollect", "code": "import pandas as pd, numpy as np\nnp.random.seed(42)\n# Ce que renvoie l''onglet DATA / l''API Kobo (200 enfants)\ndf = pd.DataFrame({''muac_mm'': np.random.normal(130,18,200).clip(60,200)})\n\ndef classer(m):\n    if m < 115: return ''MAS''\n    elif m < 125: return ''MAM''\n    return ''Normal''\n\ndf[''statut''] = df[''muac_mm''].apply(classer)\nprev = (df[''statut''].value_counts()/len(df)*100).round(1)\nprint(prev.to_string())\nmag = prev.get(''MAS'',0)+prev.get(''MAM'',0)\nprint(f\"\\nPrevalence MAG : {mag:.1f}%\")\nprint(\"ALERTE URGENCE (>15%)\" if mag>15 else \"Situation maitrisee\")"}, {"type": "callout", "variant": "real", "title": "Vous savez tout faire", "content": "Vous maîtrisez désormais le cycle complet de KoboCollect : créer un projet, concevoir un formulaire avec validation et logique, le déployer, collecter sur le terrain hors-ligne, et analyser les résultats. C''est exactement la compétence demandée dans les offres MEAL en Afrique de l''Ouest."}, {"type": "resource", "title": "pykobo — récupérer vos données par API en Python", "url": "https://github.com/pvernier/pykobo", "provider": "GitHub (open source)", "desc": "Module Python gratuit qui télécharge automatiquement les soumissions Kobo dans un DataFrame pandas. Au Projet 3, vous l''utiliserez pour automatiser tout le pipeline."}, {"type": "resource", "title": "KoboToolbox Academy (cours officiels gratuits)", "url": "https://academy.kobotoolbox.org/", "provider": "KoboToolbox", "desc": "Pour aller plus loin : les cours auto-rythmés officiels de KoboToolbox, créés par leurs experts. Un complément idéal à ce projet."}]}'::jsonb FROM sms_courses WHERE code = 'MEAL-01';